class SummaryRanges {

    private List<int[]> intervals = new ArrayList<>();

    public SummaryRanges() {

    }

    public void addNum(int value) {
        if (intervals.isEmpty() || intervals.get(intervals.size() - 1)[1] + 1 < value) {
            intervals.add(new int[]{value, value});
        } else {
            int last = intervals.get(intervals.size() - 1)[1];
            if (value == last + 1) {
                intervals.get(intervals.size() - 1)[1] = value;
            } else {
                intervals.add(new int[]{value, value});
            }
        }
    }

    public int[][] getIntervals() {
        int[][] result = new int[intervals.size()][2];
        for (int i = 0; i < intervals.size(); i++) {
            result[i] = intervals.get(i);
        }
        return result;
    }
}

